CREATE TABLE IF NOT EXISTS clients (    client_id INTEGER PRIMARY KEY,    gender CHAR(1) CHECK (gender IN ('M', 'F')));CREATE TABLE IF NOT EXISTS products (    product_id INTEGER PRIMARY KEY);CREATE TABLE IF NOT EXISTS sales (    sale_id BIGSERIAL PRIMARY KEY,    client_id INTEGER NOT NULL REFERENCES clients(client_id) ON DELETE CASCADE,    product_id INTEGER NOT NULL REFERENCES products(product_id) ON DELETE CASCADE,    purchase_date DATE NOT NULL,    purchase_time_seconds INTEGER NOT NULL,    quantity INTEGER NOT NULL CHECK (quantity >= 0),    price_per_item NUMERIC(12,2) NOT NULL CHECK (price_per_item >= 0),    discount_per_item NUMERIC(12,2) NOT NULL CHECK (discount_per_item >= 0),    total_price NUMERIC(12,2) NOT NULL CHECK (total_price >= 0),    UNIQUE (client_id, product_id, purchase_date, purchase_time_seconds));CREATE INDEX IF NOT EXISTS idx_sales_date ON sales(purchase_date);CREATE INDEX IF NOT EXISTS idx_sales_client ON sales(client_id);CREATE INDEX IF NOT EXISTS idx_sales_product ON sales(product_id);                        